#include<bits/stdc++.h>
using namespace std;
struct Edge
{
    long long u,v,w,id;
    bool operator<(const Edge&b)const
    {
        return w<b.w;
    }
}e[100010];
long long fa[100010],ans[100010];
long long find(long long x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(long long x,long long y)
{
    fa[find(x)]=find(y);
}
vector<long long> mp[100010];
long long f[100010][21],id[100010],nxt[100010],d[100010],lg[100010];
void dfs(long long x,long long fa=1)
{
    d[x]=d[fa]+1;
    nxt[x]=fa;
    f[x][0]=fa;
    for(long long i=1;i<=lg[d[x]];i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(long long i:mp[x])
    {
        long long tmp=e[i].u;
        if(tmp==x)
        {
            tmp=e[i].v;
        }
        long long v=tmp;
        if(v!=fa)
        {
            id[v]=e[i].id;
            dfs(v,x);
        }
    }
}
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=f[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
void update1(long long x,long long y,long long z)
{
    while(d[x]>d[y])
    {
        if(!ans[id[x]])
        {
            ans[id[x]]=z;
        }
        long long tx=x;
        x=nxt[tx];
        nxt[tx]=y;
    }
}
void update(long long x,long long y,long long z)
{
    long long l=lca(x,y);
    update1(x,l,z);
    update1(y,l,z);
}
long long flag[100010];
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld%lld",&e[i].u,&e[i].v,&e[i].w);
        e[i].id=i;
    }
    sort(e+1,e+1+m);
    long long sum=0;
    for(long long i=1;i<=m;i++)
    {
        if(find(e[i].u)!=find(e[i].v))
        {
            flag[i]=1;
            sum+=e[i].w;
            mp[e[i].u].push_back(i);
            mp[e[i].v].push_back(i);
            // printf("mp[%lld].push_back(%lld)\n",e[i].u,i);
            // printf("mp[%lld].push_back(%lld)\n",e[i].v,i);
            merge(e[i].u,e[i].v);
        }
    }
    dfs(1);
    for(long long i=1;i<=m;i++)
    {
        if(!flag[i])
        {
            update(e[i].u,e[i].v,e[i].w);
        }
    }
    for(long long i=1;i<=m;i++)
    {
        if(flag[i])
        {
            if(ans[e[i].id])
            {
                ans[e[i].id]+=sum-e[i].w;
            }
            else
            {
                ans[e[i].id]=-1;
            }
        }
        else
        {
            ans[e[i].id]=sum;
        }
    }
    for(long long i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
